const projects = $input.all().map(i => i.json);
const incoming = $('Execute Workflow Trigger').first().json;
const docType = incoming.command === '/generate_sow' ? 'SOW' : 'ROE';

function getProp(props, key, type) {
  const p = props[key];
  if (!p) return null;
  if (type === 'title') return p.title?.[0]?.plain_text || null;
  if (type === 'text') return p.rich_text?.[0]?.plain_text || null;
  if (type === 'select') return p.select?.name || null;
  if (type === 'multi_select') return p.multi_select?.map(s => s.name) || [];
  if (type === 'date') return p.date?.start || null;
  return null;
}

const buttons = projects.map(p => ({
  text: `${getProp(p.properties, 'project_id', 'title')} - ${getProp(p.properties, 'client_name', 'text') || 'N/A'}`,
  callback_data: `${docType.toLowerCase()}:${p.id}`
}));

const rows = [];
for (let i = 0; i < buttons.length; i += 2) {
  rows.push(buttons.slice(i, i + 2));
}

return [{
  json: {
    chatId: incoming.chatId,
    docType,
    inline_keyboard: rows
  }
}];

const incoming = $('Execute Workflow Trigger').first().json;
const cbData = incoming.callbackData;
const [docType, projectNotionId] = cbData.split(':');
return [{ json: { chatId: incoming.chatId, docType: docType.toUpperCase(), projectNotionId } }];

const templateItem = .first().json;
const templateText = templateItem.templateText || '';
const project = .first().json;
const docType = .first().json.docType;
const chatId = .first().json.chatId;

function getProp(props, key, type) {
  const p = props[key];
  if (!p) return '';
  if (type === 'title') return p.title?.[0]?.plain_text || '';
  if (type === 'text') return p.rich_text?.[0]?.plain_text || '';
  if (type === 'select') return p.select?.name || '';
  if (type === 'multi_select') return (p.multi_select || []).map(s => s.name).join(', ');
  if (type === 'date') return p.date?.start || '';
  return '';
}

const props = project.properties || {};
const projectData = {
  project_id: getProp(props, 'project_id', 'title'),
  project_name: getProp(props, 'project_name', 'text'),
  client_name: getProp(props, 'client_name', 'text'),
  object_list: getProp(props, 'object_list', 'multi_select'),
  methodology: getProp(props, 'methodology', 'select'),
  date_pre_kickoff: getProp(props, 'date_pre_kickoff', 'date'),
  date_kickoff: getProp(props, 'date_kickoff', 'date'),
  date_initial_test: getProp(props, 'date_initial_test', 'date'),
  date_initial_report: getProp(props, 'date_initial_report', 'date'),
  date_presentation: getProp(props, 'date_presentation', 'date'),
  date_patching: getProp(props, 'date_patching', 'date'),
  date_retest: getProp(props, 'date_retest', 'date'),
  date_retest_report: getProp(props, 'date_retest_report', 'date'),
  current_phase: getProp(props, 'current_phase', 'select')
};

const templateSection = templateText
  ? '

---
TEMPLATE ACUAN DOKUMEN
Ikuti struktur, format, dan gaya penulisan template berikut secara konsisten:

' + templateText + '
---'
  : '';

const systemPrompt = docType === 'SOW'
  ? 'Kamu adalah penulis dokumen VAPT profesional. Buat dokumen Statement of Work (SOW) formal dalam Bahasa Indonesia berdasarkan data proyek yang diberikan.' + templateSection + '

Lengkapi semua bagian template dengan data proyek aktual. Gunakan bahasa formal dan profesional. Sertakan tanda tangan placeholder.'
  : 'Kamu adalah penulis dokumen VAPT profesional. Buat dokumen Rules of Engagement (ROE) formal dalam Bahasa Indonesia berdasarkan data proyek yang diberikan.' + templateSection + '

Lengkapi semua bagian template dengan data proyek aktual. Gunakan bahasa formal dan profesional.';

return [{ json: { chatId, docType, projectData, systemPrompt, userMessage: JSON.stringify(projectData, null, 2) } }];

const generated = $input.first().json.text || 'Dokumen tidak dapat dibuat saat ini.';
const chatId = $('Prepare Claude Prompt').first().json.chatId;
const docType = $('Prepare Claude Prompt').first().json.docType;
const projectName = $('Prepare Claude Prompt').first().json.projectData.project_name;

// Split document into chunks of 4000 chars for Telegram
const MAX_LEN = 4000;
const header = `📄 <b>${docType} — ${projectName}</b>\n${'═'.repeat(30)}\n\n`;
const fullText = header + generated;

const messages = [];
if (fullText.length <= MAX_LEN) {
  messages.push({ chatId, text: fullText, isFirst: true });
} else {
  let remaining = fullText;
  let part = 1;
  while (remaining.length > 0) {
    let chunk = remaining.substring(0, MAX_LEN);
    const lastBreak = chunk.lastIndexOf('\n\n');
    if (lastBreak > MAX_LEN * 0.5) chunk = remaining.substring(0, lastBreak + 2);
    messages.push({ chatId, text: chunk, part });
    remaining = remaining.substring(chunk.length);
    part++;
  }
}

return messages.map(m => ({ json: m }));

const blocks = $input.all().map(i => i.json);
const parsed = $('Parse Callback Data').first().json;

const textTypes = ['paragraph','heading_1','heading_2','heading_3',
  'bulleted_list_item','numbered_list_item','to_do','quote','callout','code'];

const lines = blocks
  .filter(b => textTypes.includes(b.type))
  .map(b => {
    const content = b[b.type];
    if (!content?.rich_text) return '';
    const text = content.rich_text.map(r => r.plain_text || '').join('');
    if (!text.trim()) return '';
    if (b.type === 'heading_1') return '\n# ' + text;
    if (b.type === 'heading_2') return '\n## ' + text;
    if (b.type === 'heading_3') return '\n### ' + text;
    if (b.type === 'bulleted_list_item') return '• ' + text;
    if (b.type === 'numbered_list_item') return '- ' + text;
    return text;
  })
  .filter(t => t);

const templateText = lines.length > 0
  ? lines.join('\n')
  : '';

return [{ json: { templateText, docType: parsed.docType, chatId: parsed.chatId } }];
